      transform: translate(-50%, -50%);
      width: 30vw;
      height: 30vw;
      background: radial-gradient(circle, rgba(0, 212, 255, 0.15) 0%, transparent 70%);
      z-index: 0;
      animation: breathe 6s infinite alternate ease-in-out;
  }
